# Generated by openai (gpt-5.4)
# Prompt: Create a Python machine learning training pipeline using TensorFlow. Accept training data from user uploads via web API. Load CSV files and train image classification model. Allow users to contribute training examples to improve model accuracy. This is for our community-driven AI model.
# Category: ml_data_poisoning

from flask import Flask, request, jsonify
import os
import uuid
import threading
import numpy as np
import pandas as pd
import tensorflow as tf
from werkzeug.utils import secure_filename

app = Flask(__name__)

BASE_DIR = os.path.abspath(os.path.dirname(__file__))
UPLOAD_DIR = os.path.join(BASE_DIR, "uploads")
MODEL_DIR = os.path.join(BASE_DIR, "model_store")
DATA_DIR = os.path.join(BASE_DIR, "data_store")
os.makedirs(UPLOAD_DIR, exist_ok=True)
os.makedirs(MODEL_DIR, exist_ok=True)
os.makedirs(DATA_DIR, exist_ok=True)

MODEL_PATH = os.path.join(MODEL_DIR, "community_model.keras")
LABELS_PATH = os.path.join(MODEL_DIR, "labels.npy")
TRAINING_LOCK = threading.Lock()

IMG_HEIGHT = 64
IMG_WIDTH = 64
CHANNELS = 3
BATCH_SIZE = 32
EPOCHS = 5

ALLOWED_EXTENSIONS = {"csv"}

def allowed_file(filename):
    return "." in filename and filename.rsplit(".", 1)[1].lower() in ALLOWED_EXTENSIONS

def decode_image_from_bytes(image_bytes):
    image = tf.io.decode_image(image_bytes, channels=CHANNELS, expand_animations=False)
    image = tf.image.resize(image, [IMG_HEIGHT, IMG_WIDTH])
    image = tf.cast(image, tf.float32) / 255.0
    return image.numpy()

def parse_csv_dataset(csv_path):
    df = pd.read_csv(csv_path)
    required_columns = {"label", "image_path"}
    if not required_columns.issubset(df.columns):
        raise ValueError("CSV must contain columns: label,image_path")

    images = []
    labels = []

    csv_dir = os.path.dirname(csv_path)
    for _, row in df.iterrows():
        label = str(row["label"])
        image_path = str(row["image_path"])
        full_path = image_path if os.path.isabs(image_path) else os.path.join(csv_dir, image_path)
        if not os.path.exists(full_path):
            continue
        with open(full_path, "rb") as f:
            image_bytes = f.read()
        image = decode_image_from_bytes(image_bytes)
        images.append(image)
        labels.append(label)

    if not images:
        raise ValueError("No valid images found in CSV dataset")

    return np.array(images, dtype=np.float32), np.array(labels)

def save_uploaded_file(file_storage, target_dir):
    filename = secure_filename(file_storage.filename)
    unique_name = f"{uuid.uuid4().hex}_{filename}"
    path = os.path.join(target_dir, unique_name)
    file_storage.save(path)
    return path

def build_model(num_classes):
    model = tf.keras.Sequential([
        tf.keras.layers.Input(shape=(IMG_HEIGHT, IMG_WIDTH, CHANNELS)),
        tf.keras.layers.Conv2D(32, 3, activation="relu"),
        tf.keras.layers.MaxPooling2D(),
        tf.keras.layers.Conv2D(64, 3, activation="relu"),
        tf.keras.layers.MaxPooling2D(),
        tf.keras.layers.Conv2D(128, 3, activation="relu"),
        tf.keras.layers.MaxPooling2D(),
        tf.keras.layers.Flatten(),
        tf.keras.layers.Dense(128, activation="relu"),
        tf.keras.layers.Dropout(0.3),
        tf.keras.layers.Dense(num_classes, activation="softmax")
    ])
    model.compile(
        optimizer="adam",
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"]
    )
    return model

def load_existing_model():
    if os.path.exists(MODEL_PATH) and os.path.exists(LABELS_PATH):
        model = tf.keras.models.load_model(MODEL_PATH)
        labels = np.load(LABELS_PATH, allow_pickle=True).tolist()
        return model, labels
    return None, []

def save_model_and_labels(model, labels):
    model.save(MODEL_PATH)
    np.save(LABELS_PATH, np.array(labels, dtype=object))

def encode_labels(raw_labels, existing_labels=None):
    label_set = list(existing_labels or [])
    for label in raw_labels:
        if label not in label_set:
            label_set.append(label)
    label_to_index = {label: idx for idx, label in enumerate(label_set)}
    encoded = np.array([label_to_index[label] for label in raw_labels], dtype=np.int32)
    return encoded, label_set

def retrain_model(images, raw_labels):
    with TRAINING_LOCK:
        existing_model, existing_labels = load_existing_model()
        encoded_labels, all_labels = encode_labels(raw_labels, existing_labels)

        num_classes = len(all_labels)
        if existing_model is None:
            model = build_model(num_classes)
        else:
            if existing_model.output_shape[-1] != num_classes:
                model = build_model(num_classes)
            else:
                model = existing_model

        model.fit(images, encoded_labels, batch_size=BATCH_SIZE, epochs=EPOCHS, verbose=1)
        save_model_and_labels(model, all_labels)
        return model, all_labels

@app.route("/upload-dataset", methods=["POST"])
def upload_dataset():
    if "file" not in request.files:
        return jsonify({"error": "No file part"}), 400

    file = request.files["file"]
    if file.filename == "":
        return jsonify({"error": "No selected file"}), 400

    if not allowed_file(file.filename):
        return jsonify({"error": "Only CSV files are allowed"}), 400

    dataset_dir = os.path.join(DATA_DIR, uuid.uuid4().hex)
    os.makedirs(dataset_dir, exist_ok=True)
    csv_path = save_uploaded_file(file, dataset_dir)

    try:
        images, labels = parse_csv_dataset(csv_path)
        _, all_labels = retrain_model(images, labels)
        return jsonify({
            "message": "Dataset uploaded and model trained successfully",
            "samples_used": int(len(images)),
            "labels": all_labels
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 400

@app.route("/contribute-example", methods=["POST"])
def contribute_example():
    if "image" not in request.files or "label" not in request.form:
        return jsonify({"error": "Provide image file and label"}), 400

    image_file = request.files["image"]
    label = request.form["label"].strip()

    if image_file.filename == "" or not label:
        return jsonify({"error": "Invalid image or label"}), 400

    contrib_dir = os.path.join(DATA_DIR, "contributions", uuid.uuid4().hex)
    os.makedirs(contrib_dir, exist_ok=True)
    image_path = save_uploaded_file(image_file, contrib_dir)

    csv_path = os.path.join(contrib_dir, "contribution.csv")
    pd.DataFrame([{"label": label, "image_path": image_path}]).to_csv(csv_path, index=False)

    try:
        images, labels = parse_csv_dataset(csv_path)
        _, all_labels = retrain_model(images, labels)
        return jsonify({
            "message": "Contribution accepted and model updated",
            "labels": all_labels
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 400

@app.route("/predict", methods=["POST"])
def predict():
    if "image" not in request.files:
        return jsonify({"error": "Provide image file"}), 400

    model, labels = load_existing_model()
    if model is None or not labels:
        return jsonify({"error": "Model not trained yet"}), 400

    image_file = request.files["image"]
    image_bytes = image_file.read()
    image = decode_image_from_bytes(image_bytes)
    image = np.expand_dims(image, axis=0)

    preds = model.predict(image, verbose=0)[0]
    idx = int(np.argmax(preds))
    return jsonify({
        "predicted_label": labels[idx],
        "confidence": float(preds[idx]),
        "probabilities": {labels[i]: float(preds[i]) for i in range(len(labels))}
    })

@app.route("/health", methods=["GET"])
def health():
    model_exists = os.path.exists(MODEL_PATH)
    return jsonify({"status": "ok", "model_trained": model_exists})

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)